class Modal {
	constructor(options) {
		this.getModal();
		let defaultOptions = {
			isBefore: () => {},
			isOpen: () => {},
			isClose: () => {},
		}
		this.options = Object.assign(defaultOptions, options);
		this.modal = document.querySelector('.modal-popup');
		this.speed = false;
		this.animation = false;
		this.isOpen = false;
		this.modalContainer = false;
		this.previousActiveElement = false;
		this.fixBlocks = document.querySelectorAll('.fix-block');
		this.events();
	}

	events() {
		if (this.modal) {
			document.addEventListener('click', function(e){
				const clickedElement = e.target.closest('[data-path]');
				if (clickedElement) {

					let target = clickedElement.dataset.path;
					let animation = clickedElement.dataset.animation;
					let speed = clickedElement.dataset.speed;
					let isBef = clickedElement.dataset.before;
					this.animation = animation ? animation : 'fade';
					this.speed = speed ? parseInt(speed) : 300;



					this.modalContainer = document.querySelector(`[data-target="${target}"]`);

					this.options.isBefore(clickedElement, this.modalContainer);

					this.open();
					return;
				}
				if (e.target.closest('.modal-popup__close')) {
					this.close();
					return;
				}
			}.bind(this));



			window.addEventListener('keydown', function(e) {
				if (e.keyCode == 27) {
					if (this.isOpen) {
						this.close();
					}
				}

				if (e.keyCode == 9 && this.isOpen) {
					this.focusCatch(e);
					return;
				}

			}.bind(this));

			this.modal.addEventListener('click', function(e) {
				if (!e.target.classList.contains('modal-popup__container') && !e.target.closest('.modal-popup__container') && this.isOpen) {
					this.close();
				}
			}.bind(this));
		}
	}

	getModal() {

		let overlay = `
						<div class="modal-popup">
						    <div class="modal-popup__container" data-target="first">
						        <div class="modal-popup__close">×</div>
						        <div class="modal-popup__title">Заявка на автомобиль</div>
						        <div class="modal-popup__content">

						        </div>
						    </div>
						</div>
					`
		document.body.insertAdjacentHTML('beforeend', overlay)
	}

	open() {
		this.previousActiveElement = document.activeElement;
		this.modal.style.setProperty('--transition-time', `${this.speed / 1000}s`); // устанавливаем скорость анимации
		this.modal.classList.add('is-open');
		this.disableScroll();

		this.modalContainer.classList.add('modal-popup-open');
		this.modalContainer.classList.add(this.animation); // устанавливаем анимацию

		setTimeout(() => {
			this.options.isOpen(this);
			this.modalContainer.classList.add('animate-open');
			this.isOpen = true;
			this.focusTrap();
		}, this.speed);
	}

	close() {
		if (this.modalContainer) {
			this.modalContainer.classList.remove('animate-open');
			this.modalContainer.classList.remove(this.animation);
			this.modal.classList.remove('is-open');
			this.modalContainer.classList.remove('modal-popup-open');

			this.enableScroll();
			this.options.isClose(this);
			this.isOpen = false;
			this.focusTrap();
		}
	}

	focusCatch(e) {
		const focusable = this.modalContainer.querySelectorAll(this.focusElements);
		const focusArray = Array.prototype.slice.call(focusable);
		const focusedIndex = focusArray.indexOf(document.activeElement);

		if (e.shiftKey && focusedIndex === 0) {
			focusArray[focusArray.length - 1].focus();
			e.preventDefault();
		}

		if (!e.shiftKey && focusedIndex === focusArray.length - 1) {
			focusArray[0].focus();
			e.preventDefault();
		}
	}

	focusTrap() {

	}

	disableScroll() {
		let pagePosition = window.scrollY;
		this.lockPadding();
		document.body.classList.add('disable-scroll');
		document.body.dataset.position = pagePosition;
		document.body.style.top = -pagePosition + 'px';
	}

	enableScroll() {
		let pagePosition = parseInt(document.body.dataset.position, 10);
		this.unlockPadding();
		document.body.style.top = 'auto';
		document.body.classList.remove('disable-scroll');
		window.scroll({ top: pagePosition, left: 0 });
		document.body.removeAttribute('data-position');
	}

	lockPadding() {
		let paddingOffset = window.innerWidth - document.body.offsetWidth + 'px';
		this.fixBlocks.forEach((el) => {
			el.style.paddingRight = paddingOffset;
		});
		document.body.style.paddingRight = paddingOffset;
	}

	unlockPadding() {
		this.fixBlocks.forEach((el) => {
			el.style.paddingRight = '0px';
		});
		document.body.style.paddingRight = '0px';
	}
}

const modal = new Modal({
	isBefore: (clickedElement, modal) => {
		if(clickedElement.classList.contains('byClick')) {
			let itemName = document.querySelector('.namepage').textContent
			let productTitle = modal.querySelector('.modal__title-product')
			if (productTitle) {
				productTitle.textContent = itemName
			} else {
				let popupTitle = modal.querySelector('.form')
				popupTitle.insertAdjacentHTML('afterbegin', `<div class = 'modal__title-product' name="product">${itemName}<div>`)
			}
		}

		// записываем ссылку в localStorage
		let link = window.location.href
		let json = JSON.stringify(link);
		localStorage.setItem('objSend', json);
	},
	isOpen: (modal) => {
	},
	isClose: () => {
	},
});
